vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    vec3 main = texture( sampler_main, vUv ).xyz;
    float zoom = 1+( (vUv.x-vUv.y)*5 );
    float rot = sin(q5+vRadius)*3;
    vec2 zcr = vec2(.5,.5);
    float n = 40;
    vec2 cr = .5;

//    vec3 moz = texture( sampler_main, cr ).xyz;
    vec2 newuv = vUv;

    ///////////////////rotation////////////////
    newuv = vUv - cr;
    float s = sin(rot);
    float c = cos(rot);
    newuv = vec2( (vUv.x-cr.x)*c-(vUv.y-cr.y)*s , (vUv.x-cr.x)*s+(vUv.y-cr.y)*c  );
    newuv = newuv + cr;
    ///////////////////rotation////////////////

    ///////////////////zoom////////////////
    newuv = newuv-zcr;
    newuv = newuv * zoom;
    newuv= newuv+zcr;
    ///////////////////zoom////////////////


//    vec3 colorwarp = texture( sampler_main, newuv ).xyz *1.02;

    vec3 color = texture( sampler_rand03, newuv ).xyz;
    float mask = main.x*main.y*main.z == 1;
    vec2 cm = ((vUv*n-fract(vUv*n))%n)/n + .5/n;//vec2(((vUv.x*10)%10)/10,((vUv.y*10)%10)/10);
    vec3 moz = GetBlur1( cm )*(1-mask);

//ret = moz;
ret = ( (  color*(mask)+moz*main*(1-mask) ) );
    // darken (decay) over uTime
    ret *= 0.98; //or try: ret -= 0.004;

  fragColor = ret;
}
